import React, { useState, useCallback, useRef, useEffect } from 'react';
import {
    Sparkles, Loader2, FileDown, FileUp, Trash2, PlusCircle, ChevronDown, ChevronUp,
    GripVertical, BookOpen, CheckCircle, MessageSquareQuote, Waves, Smile,
    Network, Eye, Globe, MessagesSquare, Clock, ChevronLeft, ChevronRight,
    Pencil, Maximize2, Minimize2, X, Copy
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { RefineMode, FocusArea, CharacterProfile, ReviewPerspective, FeedbackDepth } from '../../types';
import { refineDraft } from '../../services/geminiService';

const focusAreaOptions: { id: FocusArea, label: string, icon: React.ReactNode, title: string }[] = [
  { id: 'tone', label: 'Tone', icon: <MessageSquareQuote className="w-5 h-5" />, title: 'Adjust Tone' },
  { id: 'rhythm', label: 'Rhythm', icon: <Waves className="w-5 h-5" />, title: 'Refine Rhythm' },
  { id: 'character', label: 'Character', icon: <Smile className="w-5 h-5" />, title: 'Enhance Character' },
  { id: 'network', label: 'Network', icon: <Network className="w-5 h-5" />, title: 'Improve Network' },
  { id: 'worldbuilding', label: 'Worldbuilding', icon: <Globe className="w-5 h-5" />, title: 'Worldbuild Details' },
  { id: 'logic', label: 'Logic', icon: <BookOpen className="w-5 h-5" />, title: 'Check Logic & Coherence' },
  { id: 'pace', label: 'Pace', icon: <Clock className="w-5 h-5" />, title: 'Change Pacing' },
];

interface RefinementPresetsProps {
  initialFocusAreas: FocusArea[];
  onFocusAreasChange: (focusAreas: FocusArea[]) => void;
  isLoading: boolean;
}

const RefinementPresets: React.FC<RefinementPresetsProps> = ({ initialFocusAreas, onFocusAreasChange, isLoading }) => {
  const [selectedFocusAreas, setSelectedFocusAreas] = useState<FocusArea[]>(initialFocusAreas);
  const [isDragging, setIsDragging] = useState(false);
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);

  useEffect(() => {
    setSelectedFocusAreas(initialFocusAreas);
  }, [initialFocusAreas]);

  const toggleFocusArea = useCallback((area: FocusArea) => {
    setSelectedFocusAreas(prevAreas => {
      if (prevAreas.includes(area)) {
        return prevAreas.filter(a => a !== area);
      } else {
        return [...prevAreas, area];
      }
    });
  }, []);

  useEffect(() => {
    onFocusAreasChange(selectedFocusAreas);
  }, [selectedFocusAreas, onFocusAreasChange]);

  const handleDragStart = (e: React.DragEvent<HTMLDivElement>, position: number) => {
    setIsDragging(true);
    dragItem.current = position;
  };

  const handleDragEnter = (e: React.DragEvent<HTMLDivElement>, position: number) => {
    dragOverItem.current = position;
  };

  const handleDragEnd = () => {
    setIsDragging(false);
    if (dragItem.current !== null && dragOverItem.current !== null) {
      const newList = [...selectedFocusAreas];
      const draggedItemContent = newList[dragItem.current];
      newList.splice(dragItem.current, 1);
      newList.splice(dragOverItem.current, 0, draggedItemContent);
      setSelectedFocusAreas(newList);
    }
    dragItem.current = null;
    dragOverItem.current = null;
  };

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
  };

  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-center gap-2">
        <p className="font-semibold text-lg">Focus Areas</p>
        {isLoading && <Loader2 className="animate-spin w-4 h-4" />}
      </div>

